import{_ as a,o as i,c as e,ag as n}from"./chunks/framework.CTpQozEL.js";const k=JSON.parse('{"title":"세션 관리","description":"OpenClaw가 대화 세션을 관리하는 방법","frontmatter":{"title":"세션 관리","description":"OpenClaw가 대화 세션을 관리하는 방법"},"headers":[],"relativePath":"concepts/session.md","filePath":"concepts/session.md","lastUpdated":null}'),t={name:"concepts/session.md"};function l(o,s,p,d,c,h){return i(),e("div",null,[...s[0]||(s[0]=[n(`<h1 id="세션-관리" tabindex="-1">세션 관리 <a class="header-anchor" href="#세션-관리" aria-label="Permalink to &quot;세션 관리&quot;">​</a></h1><p>OpenClaw는 대화를 <strong>세션</strong>으로 구성합니다. 각 메시지는 어디서 왔는지에 따라 세션으로 라우팅됩니다 -- DM, 그룹 채팅, cron 작업 등.</p><h2 id="메시지-라우팅-방법" tabindex="-1">메시지 라우팅 방법 <a class="header-anchor" href="#메시지-라우팅-방법" aria-label="Permalink to &quot;메시지 라우팅 방법&quot;">​</a></h2><table tabindex="0"><thead><tr><th>소스</th><th>동작</th></tr></thead><tbody><tr><td>직접 메시지</td><td>기본적으로 공유 세션</td></tr><tr><td>그룹 채팅</td><td>그룹별 격리</td></tr><tr><td>룸/채널</td><td>룸별 격리</td></tr><tr><td>Cron 작업</td><td>실행별 새 세션</td></tr><tr><td>웹훅</td><td>훅별 격리</td></tr></tbody></table><h2 id="dm-격리" tabindex="-1">DM 격리 <a class="header-anchor" href="#dm-격리" aria-label="Permalink to &quot;DM 격리&quot;">​</a></h2><p>기본적으로 모든 DM은 연속성을 위해 하나의 세션을 공유합니다. 이는 단일 사용자 설정에 적합합니다.</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>여러 사람이 에이전트에게 메시지를 보낼 수 있는 경우, DM 격리를 활성화하십시오. 이 없이는 모든 사용자가 동일한 대화 컨텍스트를 공유합니다 -- Alice의 개인 메시지가 Bob에게 표시됩니다.</p></div><p><strong>해결 방법:</strong></p><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  session</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    dmScope</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;per-channel-peer&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 채널 + 발신자별 격리</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>기타 옵션:</p><ul><li><code>main</code> (기본값) -- 모든 DM이 하나의 세션을 공유합니다.</li><li><code>per-peer</code> -- 발신자별 격리 (채널 간).</li><li><code>per-channel-peer</code> -- 채널 + 발신자별 격리 (권장).</li><li><code>per-account-channel-peer</code> -- 계정 + 채널 + 발신자별 격리.</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>동일한 사람이 여러 채널에서 연락하는 경우, <code>session.identityLinks</code>를 사용하여 자격을 연결하면 하나의 세션을 공유합니다.</p></div><p><code>openclaw security audit</code>으로 설정을 확인하십시오.</p><h2 id="세션-라이프사이클" tabindex="-1">세션 라이프사이클 <a class="header-anchor" href="#세션-라이프사이클" aria-label="Permalink to &quot;세션 라이프사이클&quot;">​</a></h2><p>세션은 만료될 때까지 재사용됩니다:</p><ul><li><strong>일별 재설정</strong> (기본값) -- 게이트웨이 호스트의 로컬 시간 오전 4:00에 새 세션.</li><li><strong>유휴 재설정</strong> (선택적) -- 비활성 기간 후 새 세션. <code>session.reset.idleMinutes</code> 설정.</li><li><strong>수동 재설정</strong> -- 채팅에서 <code>/new</code> 또는 <code>/reset</code> 입력. <code>/new &amp;lt;model&amp;gt;</code>은 모델도 전환합니다.</li></ul><p>일별 및 유휴 재설정 모두 구성된 경우, 먼저 만료되는 것이 우선합니다.</p><h2 id="상태가-있는-위치" tabindex="-1">상태가 있는 위치 <a class="header-anchor" href="#상태가-있는-위치" aria-label="Permalink to &quot;상태가 있는 위치&quot;">​</a></h2><p>모든 세션 상태는 <strong>게이트웨이</strong>가 소유합니다. UI 클라이언트는 게이트웨이에 세션 데이터를 쿼리합니다.</p><ul><li><strong>저장소:</strong> <code>~/.openclaw/agents/&amp;lt;agentId&amp;gt;/sessions/sessions.json</code></li><li><strong>트랜스크립트:</strong> <code>~/.openclaw/agents/&amp;lt;agentId&amp;gt;/sessions/&amp;lt;sessionId&amp;gt;.jsonl</code></li></ul><h2 id="세션-유지-관리" tabindex="-1">세션 유지 관리 <a class="header-anchor" href="#세션-유지-관리" aria-label="Permalink to &quot;세션 유지 관리&quot;">​</a></h2><p>OpenClaw는 시간이 지남에 따라 세션 저장소를 자동으로 제한합니다. 기본적으로 <code>warn</code> 모드로 실행됩니다 (정리될 것을 보고). 자동 정리를 위해 <code>session.maintenance.mode</code>를 <code>&quot;enforce&quot;</code>로 설정하십시오:</p><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  session</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    maintenance</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      mode</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;enforce&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      pruneAfter</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;30d&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      maxEntries</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">500</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><code>openclaw sessions cleanup --dry-run</code>으로 미리 볼 수 있습니다.</p><h2 id="세션-검사" tabindex="-1">세션 검사 <a class="header-anchor" href="#세션-검사" aria-label="Permalink to &quot;세션 검사&quot;">​</a></h2><ul><li><code>openclaw status</code> -- 세션 저장소 경로 및 최근 활동.</li><li><code>openclaw sessions --json</code> -- 모든 세션 (<code>--active &amp;lt;minutes&amp;gt;</code>로 필터링).</li><li>채팅에서 <code>/status</code> -- 컨텍스트 사용량, 모델, 토글.</li><li>채팅에서 <code>/context list</code> -- 시스템 프롬프트에 있는 것.</li></ul><h2 id="추가-읽기" tabindex="-1">추가 읽기 <a class="header-anchor" href="#추가-읽기" aria-label="Permalink to &quot;추가 읽기&quot;">​</a></h2><ul><li><a href="/openclaw-docs-ko/concepts/session-pruning">세션 프루닝</a> -- 도구 결과 정리</li><li><a href="/openclaw-docs-ko/concepts/compaction">컴팩션</a> -- 긴 대화 요약</li><li><a href="/openclaw-docs-ko/concepts/session-tool">세션 도구</a> -- 크로스 세션 작업을 위한 에이전트 도구</li><li><a href="/openclaw-docs-ko/reference/session-management-compaction">세션 관리 심층 분석</a> -- 저장소 스키마, 트랜스크립트, 전송 정책, 출처 메타데이터, 고급 구성</li><li><a href="/openclaw-docs-ko/concepts/multi-agent">멀티 에이전트</a> — 에이전트 간 라우팅 및 세션 격리</li><li><a href="/openclaw-docs-ko/automation/tasks">백그라운드 태스크</a> — 분리된 작업이 세션 참조로 태스크 레코드를 생성하는 방법</li><li><a href="/openclaw-docs-ko/channels/channel-routing">채널 라우팅</a> — 인바운드 메시지가 세션으로 라우팅되는 방법</li></ul>`,28)])])}const E=a(t,[["render",l]]);export{k as __pageData,E as default};
